insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'chiyoda'), 'tokyo-chiyoda-prenatal-postpartum-helper', '育児支援訪問事業（産前産後の家事・育児支援ヘルパー派遣）', '千代田区が実施する育児支援訪問事業です。妊産婦や乳幼児・児童のいる家庭で、保護者が一時的に育児が困難になり、かつ親族など他に支援する人がいない場合に、支援員が家庭を訪問して家事・育児（授乳の手伝い、食事の介助、沐浴の補助、おむつ替え、園への送迎や健診の付き添いなど）を支援します。産前産後支援は年間合計60時間（多胎出産は120時間）まで利用できる可能性があると公式に記載されています。区が別に行う産後ケア事業（母子の心身ケア）とは別の事業です。対象や利用時間・料金は世帯状況や区の認定により異なるため、利用前に千代田区へ確認してください。', '出産の前後や子育て中で、家事や育児を手伝ってくれる人が身近にいないとき、千代田区の支援員が家に来て家事や育児を手伝ってくれる制度です。産前産後は年間60時間（双子などは120時間）まで利用できる可能性があります。利用料は世帯の状況によって1時間0円・500円・1,000円のいずれかです。利用したいときは児童・家庭支援センターに早めに申し込みます。', 'service', '千代田区に住民票があり居住している、妊産婦（生後1歳未満）または義務教育終了前の児童がいる家庭で、保護者が一時的に育児が困難であると区が認定し、かつ親族など他に支援する人がいない世帯が対象となる可能性があります。詳しい対象条件は千代田区公式サイトで確認してください。', '支援員が家庭を訪問し、家事・育児を支援するサービスです。利用料は1時間あたり、生活保護・住民税非課税世帯は0円、均等割のみ課税の世帯は500円、その他の世帯は1,000円と公式に記載されています（世帯の課税状況により異なる可能性があります）。', '利用開始希望日のおよそ1か月前から5営業日（約1週間）前までに申し込むよう公式に記載されています。具体的な期限は区にご確認ください。', '利用開始希望日の概ね1か月前から数営業日前までに、児童・家庭支援センターへ申し込む方式と公式に記載されています。申請の詳細・締切は千代田区公式サイトおよび窓口で確認してください。', '利用申請書、母子健康手帳の写し、出生届出済証明、児童連絡票（該当する場合）などが必要となる可能性があると公式に記載されています。義務教育終了前児童の支援では疾病・介護等の根拠書類（診断書等）が必要な場合があります。必要書類は千代田区へ確認してください。', FALSE, '千代田区 教育委員会事務局子ども部 児童・家庭支援センター 子ども相談窓口', '03-5211-4116', 'https://www.city.chiyoda.lg.jp/koho/kosodate/kosodate/ninshin/homon.html', 'https://www.city.chiyoda.lg.jp/koho/kosodate/kosodate/ninshin/homon.html', '育児支援訪問事業 - 千代田区', '2026-06-24', 'high', ARRAY['targetPeople', 'benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '対象条件・利用できる時間・利用料は世帯状況や区の認定により異なります。本ページは概要であり、最新かつ正確な情報は必ず千代田区の公式サイトおよび窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
