insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot prenatal-postpartum-helper import', '{"slug":"tokyo-chiyoda-prenatal-postpartum-helper","status":"published","title":"育児支援訪問事業（産前産後の家事・育児支援ヘルパー派遣）","officialUrl":"https://www.city.chiyoda.lg.jp/koho/kosodate/kosodate/ninshin/homon.html","topic":"prenatal-postpartum-helper"}'::jsonb, 'pilot:tokyo-chiyoda-prenatal-postpartum-helper:dG9reW8tY2hpeW9kYS1wcmVuYXRhbC1wb3N0cGFy' from public.support_programs sp where sp.slug='tokyo-chiyoda-prenatal-postpartum-helper' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'chuo'), 'tokyo-chuo-prenatal-postpartum-helper', '育児支援ヘルパー（中央区）', '中央区が、妊娠中から産後6カ月までの乳児がいる家庭にヘルパーを派遣し、育児（授乳・もく浴・おむつ交換・未就学の兄姉の世話等）と家事（食事の支度・掃除・洗濯等）を支援する区独自の事業です。母親の負担を軽減し、家庭での安定した子育てを支えることを目的としています。対象・利用回数・利用料などの詳細は中央区公式ページで確認してください。', '中央区にお住まいで、妊娠中から赤ちゃんが生後6カ月になるまでの家庭が対象となる可能性があります。区が契約した事業者からヘルパーが来て、授乳・もく浴・おむつ交換や、食事の支度・掃除・洗濯などを手伝ってくれる制度です。利用には事前の登録申請が必要で、利用料は世帯の所得に応じて変わります。詳しい対象条件や料金は公式ページでご確認ください。', 'service', '中央区在住で、出産前（母子健康手帳交付時）から出産後6カ月までの乳児がいて、育児・家事の支援を必要とする家庭が対象となる可能性があります。詳しい対象条件は中央区公式ページで確認してください。', 'サービス（ヘルパー派遣）。利用料は世帯所得により3段階で、所得が一定以下の世帯は無料、その他は1回2時間2,000円・3時間3,000円、または2時間5,000円・3時間7,500円と公式で案内されています（金額・区分は変更の可能性があるため公式で要確認）。', '利用を希望する日の（土日祝・年末年始を除く）10日前までに登録を済ませる必要があると公式で案内されています。予約は派遣事業者へ利用日の数日前まで（公式で要確認）。', '子ども家庭支援センターの窓口または郵送で利用登録申請を行います。登録後、利用日ごとに派遣事業者へ予約を申し込みます。手続きの詳細は公式ページで確認してください。', '利用登録申請書、母子健康手帳、所得を確認できる書類（課税証明書または源泉徴収票等）が必要と案内されています。最新の必要書類は公式ページで確認してください。', FALSE, '中央区 子ども家庭支援センター「きらら中央」', '03-3542-6321', 'https://www.city.chuo.lg.jp/a0025/kosodate/shussan/shussanshien/ikujisien.html', 'https://www.city.chuo.lg.jp/a0025/kosodate/shussan/shussanshien/ikujisien.html', '育児支援ヘルパー - 中央区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText', 'targetPeople']::text[], '本ページは中央区の公式情報をもとにした概要です。対象条件・利用回数・利用時間・利用料・所得区分・申請手続きは変更される場合があります。最新かつ正確な情報は中央区公式ページでご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
