insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'minato'), 'tokyo-minato-prenatal-postpartum-helper', '港区 産前産後家事・育児支援サービス', '港区在住で妊娠中または出産後の家庭を対象に、ホームヘルパー(家事支援)または産後ドゥーラ(家事・育児支援)が自宅を訪問し、家事や育児を支援する区の事業です。利用には事前のID登録が必要で、対象・利用料・利用時間は世帯状況や時期によって異なる可能性があるため、詳細は公式ページでご確認ください。', '妊娠中から出産後の子育て家庭に、家事や育児を手伝うヘルパー(または産後ドゥーラ)を自宅に派遣してくれる港区のサービスです。掃除・洗濯・買い物・食事づくりのほか、産後ドゥーラなら沐浴の手伝いや育児相談などにも対応する可能性があります。利用には事前のID登録が必要で、登録後に事業者を選んで予約します。', 'service', '港区在住で妊娠中または出産後の方がいる家庭が対象となる可能性があります。利用期間は子が3歳になる前日までが上限とされ、流産・死産の場合も対応すると公式ページに記載されています。具体的な対象要件は世帯状況により異なる場合があるため、公式で確認してください。', 'ホームヘルパー(家事支援)の利用料は単胎家庭で2時間1,500円から4時間3,000円、産後ドゥーラ(家事・育児支援)は2時間2,000円から4時間4,000円と公式ページに記載されています。多胎家庭や住民税非課税世帯は半額、生活保護世帯は無料とされています(確認日時点)。世帯状況により異なるため公式で確認してください。', '利用期間は子が3歳になる前日までが上限と公式ページに記載されています。申込時期の詳細は公式でご確認ください。', 'オンラインでID登録を行い登録番号を取得した後、公式の事業者リストから事業者を選んで直接予約する流れと公式ページに記載されています。詳細・最新の手順は公式ページでご確認ください。', '妊娠中に申請する場合は母子健康手帳の表紙と保護者欄の添付が必要と公式ページに記載されています。最新の必要書類は公式でご確認ください。', TRUE, '港区 子ども家庭支援センター 子ども家庭サービス係', '03-5962-7201', 'https://www.city.minato.tokyo.jp/kosodatesien/kenko/ninshin/shussan/mama-support.html', 'https://www.city.minato.tokyo.jp/kosodatesien/kenko/ninshin/shussan/mama-support.html', '港区ホームページ／産前産後家事・育児支援サービス', '2026-06-24', 'high', ARRAY['targetPeople', 'benefitAmountText', 'applicationDeadlineText']::text[], '本ページは港区公式サイトの情報をもとにした概要です。対象・利用料・利用時間・必要書類などは変更される場合があり、世帯状況によって異なります。最新かつ正確な情報は必ず港区公式ページでご確認ください。当サイトは申請の代行や受給の保証は行いません。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
