insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot prenatal-postpartum-helper import', '{"slug":"tokyo-minato-prenatal-postpartum-helper","status":"published","title":"港区 産前産後家事・育児支援サービス","officialUrl":"https://www.city.minato.tokyo.jp/kosodatesien/kenko/ninshin/shussan/mama-support.html","topic":"prenatal-postpartum-helper"}'::jsonb, 'pilot:tokyo-minato-prenatal-postpartum-helper:dG9reW8tbWluYXRvLXByZW5hdGFsLXBvc3RwYXJ0' from public.support_programs sp where sp.slug='tokyo-minato-prenatal-postpartum-helper' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'shinjuku'), 'tokyo-shinjuku-prenatal-postpartum-helper', '新宿区 産前産後支援事業（家事・育児ヘルパー／産後ドゥーラ派遣）', '新宿区が、妊娠中から産後の家庭に援助者（ヘルパー又は産後ドゥーラ）を派遣し、家事や育児を支援する区独自事業です。育児支援（沐浴・授乳・お子さまのお世話・見守り・育児相談など）と家事支援（炊事・洗濯・掃除・寝具の始末・買い物など）を、利用者の状況に合わせて組み合わせて利用できる可能性があります。母子の心身をケアする産後ケア事業（宿泊・通所・訪問）とは別の制度です。対象や利用料金、利用できる時間・回数などの詳細は家庭構成等により異なるため、必ず新宿区の公式ページでご確認ください。', '赤ちゃんが生まれる前後の時期に、ヘルパーや産後ドゥーラが家に来て、料理・洗濯・掃除などの家事や、沐浴・授乳・見守りなどの育児を手伝ってくれる新宿区のサービスです。利用には事前の登録申請が必要で、料金や利用できる回数は家庭の状況によって変わります。くわしくは新宿区の公式ページをご確認ください。', 'service', '新宿区に住民登録がある妊婦、1歳未満の子を養育している方、一定年齢の兄姉を同居養育する多子家庭、多胎児を養育している方などが対象となる可能性があります。対象の詳しい条件は公式ページでご確認ください。', '利用料金は、産後ドゥーラが1時間あたり1,500円、ヘルパーが1時間あたり1,000円とされています（公式で確認）。非課税世帯・生活保護世帯などを対象とした減額・免除の制度がある場合があります。料金や上限時間は家庭構成等により異なるため公式ページでご確認ください。', '', '事前の利用登録申請が必要です。窓口申請（子ども総合センター等）、郵送申請、電子申請（LOGOフォーム）のいずれかで申請できる可能性があります。申請から決定まで一定の期間（公式では概ね2週間ほど）がかかるとされています。最新の手続き・必要書類は公式ページでご確認ください。', '', TRUE, '新宿区立子ども総合センター 子育て支援課 子育て支援係（産前産後支援担当）', '03-3232-0695', 'https://www.city.shinjuku.lg.jp/kodomo/file03_02_00001.html', 'https://www.city.shinjuku.lg.jp/kodomo/file03_02_00001.html', '産前産後支援事業 - 新宿区', '2026-06-24', 'high', ARRAY['targetPeople', 'benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本情報は新宿区公式ページ（2026-06-24確認）に基づく概要です。対象・料金・利用時間・申請方法は変更される場合があるため、利用前に必ず公式ページや問い合わせ先でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
