insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot prenatal-postpartum-helper import', '{"slug":"tokyo-shinjuku-prenatal-postpartum-helper","status":"published","title":"新宿区 産前産後支援事業（家事・育児ヘルパー／産後ドゥーラ派遣）","officialUrl":"https://www.city.shinjuku.lg.jp/kodomo/file03_02_00001.html","topic":"prenatal-postpartum-helper"}'::jsonb, 'pilot:tokyo-shinjuku-prenatal-postpartum-helper:dG9reW8tc2hpbmp1a3UtcHJlbmF0YWwtcG9zdHBh' from public.support_programs sp where sp.slug='tokyo-shinjuku-prenatal-postpartum-helper' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'bunkyo'), 'tokyo-bunkyo-prenatal-postpartum-helper', 'おうち家事・育児サポート事業（産前産後の家事・育児支援）', '文京区の在宅家事・育児支援事業。妊娠中または満3歳未満の乳幼児がいる世帯を対象に、サポート券を使って区が指定した民間事業者のヘルパーが家事（炊事・洗濯・掃除等）や育児（おむつ替え・沐浴・授乳等）を支援する事業として公式に案内されています。産後ケア事業（母体・新生児の心身ケア）とは別の事業です。', '妊娠中や、3歳になるまでの小さなお子さんがいるご家庭に、ヘルパーが訪問して家事や育児を手伝ってくれる文京区の制度です。サポート券を使い、1時間1,000円で利用できる仕組みとして公式に案内されています（非課税世帯は半額助成の記載あり）。対象や利用できる時間・料金などの詳しい条件は、必ず文京区の公式ページでご確認ください。', 'service', '文京区内に住所のある妊婦、または満3歳未満の乳幼児がいる世帯が対象となる可能性があります（公式では満3歳未満の多胎児がいる世帯・多胎児を妊娠している方は対象外と案内）。対象の詳細は文京区公式で確認してください。', '家事・育児サポート券を使って1時間あたり1,000円で利用できる仕組みとして公式に案内されています（非課税世帯は半額助成の記載あり）。利用できる枚数・時間数（初回申請分や追加申請で最大96時間分など）や1回の利用時間（2・3・4時間から選択）には条件があるため、詳細は公式で確認してください。', '申込期限・利用期限は公式ページで確認してください。', '電子申請（公式で推奨）、郵送、または窓口での申請に対応していると案内されています。詳しい手続きは文京区公式ページで確認してください。', '妊娠中に申請する場合は母子健康手帳の表紙のコピーが必要と案内されています。最新の必要書類は公式で確認してください。', TRUE, '文京区 こども未来部 こども若者支援課', '03-5803-1288', 'https://www.city.bunkyo.lg.jp/b022/p001690.html', 'https://www.city.bunkyo.lg.jp/b022/p001690.html', 'おうち家事・育児サポート事業 | 文京区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'targetPeople', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本ページの内容は文京区公式サイトの情報をもとにした概要です。対象・利用料・利用時間・申請方法などの最新かつ正確な情報は、必ず文京区の公式ページでご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
