insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'taito'), 'tokyo-taito-prenatal-postpartum-helper', '産前産後支援ヘルパー"あったかハンド"（台東区）', '台東区が実施する産前産後の家事・育児支援ヘルパー派遣事業です。家庭内に妊婦や乳幼児を介助する人がいないために育児や家事が困難な家庭にヘルパーを派遣し、家事や育児を支援します。対象や利用料、利用できる時間・回数などの詳細は台東区公式サイトで確認してください。', '妊娠中から産後の家庭にヘルパーが訪問し、家事や育児を手伝ってくれる台東区の制度です。区内在住で、家庭内に妊婦や乳幼児を介助できる人がいないため育児・家事が困難な方が対象となる可能性があります。利用料は1時間1人あたり300円（減免制度あり）とされていますが、対象や利用条件は変更されることがあるため、必ず台東区公式サイトでご確認ください。', 'service', '区内在住で、家庭内に妊婦または乳幼児を介助する方がいないため育児や家事が困難な方が対象となる可能性があります（公式では妊婦は単胎児出産予定者、乳幼児は生後3年の前日までと案内）。多胎世帯は別の案内ページがあります。詳細は台東区公式サイトで確認してください。', '利用料は1時間1人あたり300円とされています（減免制度あり）。利用時間の上限は各期間（母子健康手帳取得〜1歳未満／1〜2歳未満／2〜3歳未満）ごとに96時間、1日あたり最大4時間と案内されています。金額・条件は変更される場合があるため公式サイトで確認してください。', '公式ページに明確な申請期限の記載は確認できませんでした。利用可能期間は公式サイトで確認してください。', 'オンライン申請（mila-e申請）で利用申請を行い、電子クーポンの発行後に各事業者へ直接連絡して利用予約をする方法が公式で案内されています。申請方法は変更される場合があるため公式サイトで確認してください。', '必要書類の詳細は公式ページで確認できませんでした。台東区公式サイトまたは問い合わせ先でご確認ください。', TRUE, '浅草保健相談センター', '03-3844-8171', NULL, 'https://www.city.taito.lg.jp/kosodatekyouiku/kosodate/nenrei/ninshinki/soudan_shien/helper_ippan.html', '産前産後支援ヘルパー"あったかハンド"【一般向け（多胎を除く）】 台東区ホームページ', '2026-06-24', 'high', ARRAY['requiredDocumentsText', 'applicationDeadlineText', 'targetPeople']::text[], '本情報は台東区公式サイトの掲載内容に基づく概要です（2026-06-25時点で確認）。対象・利用料・利用時間や回数の上限などは変更される場合があり、多胎世帯は条件が異なります。最新かつ正確な情報は必ず台東区公式サイトでご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
