insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'sumida'), 'tokyo-sumida-prenatal-postpartum-helper', '墨田区 家事・育児サポーター事業', '墨田区が、妊娠中の方や0〜2歳児を養育する家庭に、サポーターを自宅へ派遣し、家事(炊事・洗濯・掃除・買い物)や育児(沐浴・授乳の補助、お子さんや兄姉のお世話、同行支援など)を支援する区独自事業です。区が交付する利用券を提携事業者に提出することで、一定の自己負担で利用できます。利用には事前の登録申請が必要です。', '妊娠中や、0〜2歳の小さなお子さんを育てている家庭に、サポーターが家に来て、掃除・洗濯・買い物などの家事や、沐浴・授乳の手伝いなどの育児を手伝ってくれる墨田区のサービスです。利用には事前の登録申請が必要で、料金は派遣事業者によって異なります。詳しい対象条件・料金・利用時間は墨田区公式ページでご確認ください。', 'service', '墨田区に住所があり、妊娠中の方または0歳から2歳までのお子さんを養育している家庭が対象となる可能性があります。詳しい対象条件は墨田区公式ページでご確認ください。', 'サポーターを自宅へ派遣して家事支援・育児支援を行うサービスです(現金給付ではありません)。利用者の負担する利用料金はサポーター派遣事業者ごとに異なります。利用時間の上限は、多胎児以外で妊娠期〜0歳・1歳・2歳それぞれ96時間、多胎児で妊娠期〜0歳240時間・1歳/2歳それぞれ192時間とされています(公式で要確認)。', '公式ページに申請期限の明示的な記載は確認できませんでした。最新の取り扱いは墨田区公式ページ・子育て支援総合センターでご確認ください。', '子育て支援総合センターへ、申請フォーム・電話・窓口のいずれかで事前に登録申請を行います。区が交付する利用券を、提携するサポーター派遣事業者に提出して利用します。詳細・最新の手続きは墨田区公式ページでご確認ください。', '妊娠期の登録申請には親子(母子)健康手帳が必要とされています。その他の必要書類は墨田区公式ページでご確認ください。', TRUE, '墨田区 子育て支援総合センター', '03-3622-1150', 'https://www.city.sumida.lg.jp/kosodate_kyouiku/kosodate_site/sodan/kajiikuji.html', 'https://www.city.sumida.lg.jp/kosodate_kyouiku/kosodate_site/sodan/kajiikuji.html', '家事・育児サポーター事業 - 墨田区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText']::text[], '本ページは公開情報の要約であり、支援を保証するものではありません。対象条件・利用料金・利用時間・申請方法は変更される場合があるため、必ず墨田区公式ページまたは子育て支援総合センターで最新情報をご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
