insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'koto'), 'tokyo-koto-prenatal-postpartum-helper', 'こうとう家事・育児サポート事業（家事・育児支援ヘルパー派遣）', '江東区が、区内在住で3歳未満の子どもを養育する家庭に訪問支援者（ヘルパー）を派遣し、掃除・買い物・洗濯・調理などの家事支援や、授乳の見守り・沐浴などの育児支援、子育て相談を行う区独自事業です。利用料は1時間あたり500円で、訪問1回あたり2時間以上（1時間単位）から利用できます。月の利用時間の上限は子どもの年齢やきょうだいの構成によって異なります（公式で確認）。母子の心身をケアする『産後ケア事業』とは別の、家事・育児を手伝うヘルパー派遣の制度です。対象や利用料、利用できる時間・回数の上限は区の運用により変わる場合があるため、必ず江東区の公式ページで最新の内容をご確認ください。', '赤ちゃんや小さな子どもがいて家事・育児が大変なとき、区がヘルパーさんを家に派遣して掃除・洗濯・調理や沐浴・授乳の見守りなどを手伝ってくれる制度です。江東区では3歳未満の子を育てる家庭が対象で、利用料は1時間500円です。妊娠中の申請はできず、出生届を出してから申請します。詳しい条件は公式ページで確認してください。', 'service', '江東区内在住で、3歳未満の子どもを養育している家庭が対象です。本事業は産後（出生届出後）の申請が前提で、妊娠中（産前）の申請はできません。多胎児（双子・三つ子）家庭向けには妊娠中から利用できる別事業があります。詳細は公式でご確認ください。', '利用料1時間あたり500円（公式で確認）', '随時。利用希望日より余裕をもった申し込みが推奨されています（公式で確認）。', '原則として電子申請で利用登録を申請します。江東区役所こども家庭支援課の窓口持参や郵送による申請も可能です。詳細・最新の手続きは公式ページでご確認ください。', '電子申請の場合は添付書類不要とされています。窓口申請では利用申請書が必要です。最新の必要書類は公式でご確認ください。', TRUE, '江東区 こども未来部 こども家庭支援課 こども家庭係', '03-3647-9230', 'https://www.city.koto.lg.jp/281012/kajiikuji-kateihoumon.html', 'https://www.city.koto.lg.jp/281012/kajiikuji-kateihoumon.html', 'こうとう家事・育児サポート事業 - 江東区', '2026-06-24', 'high', ARRAY['applicationDeadlineText', '利用時間・回数の上限']::text[], '本情報は江東区公式ページ（更新日2026-06-04）を基に作成した概要です。対象・利用料・利用時間や回数の上限・申請方法は変更される場合があります。申請により必ず利用できることを保証するものではありません。最新かつ正確な内容は必ず江東区の公式ページ・窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
