insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'shinagawa'), 'tokyo-shinagawa-prenatal-postpartum-helper', 'すこやかサポート（育児支援ヘルパー）', '産前産後に体調不良などで日常生活に支障があり、他から援助を受けられない品川区内の家庭にヘルパーを派遣し、家事や育児を支援する区の事業です。支援の具体的な内容や対象の詳細は品川区の公式ページでご確認ください。', '妊娠中や出産後で体調がすぐれず、家事や育児を手伝ってくれる人が身近にいないご家庭に、品川区がヘルパーを派遣してくれる制度です。利用には事前の登録が必要で、まずは家庭あんしんセンターに電話で相談します。公式ページの案内では利用料は1時間あたりの自己負担があり（減免制度もあるとされています）、利用できる時期・日数・時間は決められています。手伝ってもらえる具体的な内容や、利用できる時期・日数・時間・料金は変わることがあるため、申し込む前に必ず品川区の公式ページで最新の内容をご確認ください。', 'service', '品川区内に住み、産前産後に体調不良などで日常生活に支障があり、他から援助を受けられない家庭が対象とされています。対象の詳細（利用できる時期や世帯の条件など）は品川区の公式ページでご確認ください。', '公式ページの記載では、利用料は1時間410円で、減免制度があるとされています（金額・減免条件は変更される場合があるため公式で確認してください）。', '利用期間は、産前は出産予定日の1か月前～出産日、産後は退院した翌日～1年以内とされています。申込期限の詳細は公式でご確認ください。', '利用には事前登録が必要です。公式ページによると、家庭あんしんセンター（電話03-5749-1032、午前9時～午後6時／日・祝・年末年始を除く）に電話で問い合わせ・登録する方法が案内されています。具体的な登録手続き・必要書類は公式でご確認ください。', '必要書類は公式ページに明示がないため、事前登録時に家庭あんしんセンターへご確認ください。', FALSE, '品川区 家庭あんしんセンター', '03-5749-1032', NULL, 'http://www.city.shinagawa.tokyo.jp/PC/kodomo/kodomo-kateisoudan/hpg000023819.html', 'すこやかサポート(育児支援ヘルパー)｜品川区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText', 'onlineApplicationAvailable', 'targetPeople']::text[], '本内容は2026-06-25時点で品川区公式ページ（最終更新：令和4年4月1日）を基に作成した参考情報です。支援内容・対象・利用日数・利用時間・料金・減免などの条件は変更される場合があります。利用前に必ず品川区の公式ページおよび家庭あんしんセンターで最新情報をご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
