insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'meguro'), 'tokyo-meguro-prenatal-postpartum-helper', '目黒区 家事育児支援ヘルパー派遣事業', '目黒区が、妊娠中から産後の家庭にヘルパーを派遣し、育児（沐浴補助・ミルク準備・おむつ交換）や家事（食事づくり・洗濯・買い物・簡単な清掃）、健診時の付き添い、きょうだいの世話などを支援する区独自の事業です。産後ケア事業とは別の制度で、家事・育児の負担軽減を目的としています。', '目黒区にお住まいで、妊娠中や出産後に家事・育児の手助けが必要なご家庭に、ヘルパーを自宅へ派遣してくれる目黒区の制度です。赤ちゃんのお世話や食事づくり・洗濯・買い物・掃除、健診の付き添い、上のお子さんのお世話などを手伝ってもらえます。対象や利用時間・利用料などは公式ページでご確認ください。', 'service', '目黒区在住で、産前の家事援助や産後の育児・家事援助等の支援を必要とする妊産婦・赤ちゃんと養育者がいる家庭が対象となる可能性があります。詳しい要件は公式ページでご確認ください。', '利用料は1時間あたり500円（公式ページ記載）。利用開始から6時間までは無料、生活保護受給世帯・住民税非課税世帯は無料とされています。最新の料金は公式でご確認ください。', '利用期間や予約の締切は対象（単胎・多胎）により異なる可能性があります。公式ページでご確認ください。', 'オンライン申請、子ども若者課児童手当・医療証係の窓口、または郵送で申請します（公式ページ参照）。利用にあたっては事前の申請と利用決定が必要とされています。', '申請書（公式ページからPDFダウンロード可）。その他の必要書類は公式ページでご確認ください。', TRUE, '目黒区 子ども若者課 児童手当・医療証係', '03-5722-8709', NULL, 'https://www.city.meguro.tokyo.jp/kosodateshien/kosodatekyouiku/kosodate/sanzensangosien.html', '家事育児支援ヘルパー派遣事業 | 目黒区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText', 'targetPeople']::text[], '本内容は公式ページに基づく概要です。対象・利用時間・利用回数・利用料・対象期間などは変更される場合があり、最終的な可否は区の審査・確認によります。最新かつ正確な情報は目黒区公式ページでご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
