insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot prenatal-postpartum-helper import', '{"slug":"tokyo-meguro-prenatal-postpartum-helper","status":"published","title":"目黒区 家事育児支援ヘルパー派遣事業","officialUrl":"https://www.city.meguro.tokyo.jp/kosodateshien/kosodatekyouiku/kosodate/sanzensangosien.html","topic":"prenatal-postpartum-helper"}'::jsonb, 'pilot:tokyo-meguro-prenatal-postpartum-helper:dG9reW8tbWVndXJvLXByZW5hdGFsLXBvc3RwYXJ0' from public.support_programs sp where sp.slug='tokyo-meguro-prenatal-postpartum-helper' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'ota'), 'tokyo-ota-prenatal-postpartum-helper', '大田区 産前産後家事・育児援助事業（にこにこサポート）', '妊娠中から産後1年以内の家庭に、産後ドゥーラの資格を持つ支援員を自宅へ派遣し、家事や育児を支援する大田区独自の事業です。対象や利用料・利用時間などは公式ページでの確認が必要です。', '大田区にお住まいで妊娠中から産後1年以内の方が対象となる可能性がある、家事・育児のヘルパー（支援員）派遣サービスです。食事の支度や買い物、掃除・洗濯、授乳やおむつ交換のお手伝い、きょうだいのお世話、育児相談などを支援員が自宅で行います。利用には区への登録申請が必要で、利用料や利用できる時間数などの詳しい条件は大田区公式ページでご確認ください。', 'service', '大田区にお住まいで、妊娠中から産後1年以内の方が対象となる可能性があります（母子健康手帳交付後から産後1年に達する前日まで）。詳しい対象要件は公式ページでご確認ください。', '支援員（産後ドゥーラ）を自宅へ派遣し、家事・育児を支援するサービスです。利用料は公式ページで1時間につき1,000円とされ、住民税非課税世帯・生活保護世帯は免除、初回利用時は2時間無料との案内があります（金額・条件は変更の可能性があるため公式で確認）。', '妊娠中から産後1年に達する前日までが利用対象期間とされています（詳細は公式ページで確認）。', '区への利用者登録申請が必要です。電子申請（ぴったりサービス）のほか、郵送・窓口でも申請を受け付けています。申請後、利用決定通知および利用カードが郵送されます。最新の手続きは公式ページでご確認ください。', '住民税非課税世帯として利用料免除を希望する場合は、世帯全員分の非課税証明書の添付が必要とされています。必要書類は公式ページで確認してください。', TRUE, '大田区 子育ち支援課 子育ち支援担当（こども家庭支援）', '03-5744-1778', 'https://www.city.ota.tokyo.jp/seikatsu/kodomo/shien/sango_enjo-nk.html', 'https://www.city.ota.tokyo.jp/seikatsu/kodomo/shien/sango_enjo-nk.html', '大田区産前産後家事・育児援助事業（にこにこサポート）', '2026-06-24', 'high', ARRAY['targetPeople', 'benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本情報は大田区公式ページをもとにした概要です。対象要件・利用料・利用時間や回数・申請方法は変更される場合があります。最新かつ正確な内容は必ず大田区公式ページおよび担当課でご確認ください。利用を保証するものではありません。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
