insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'shibuya'), 'tokyo-shibuya-prenatal-postpartum-helper', '産前産後家事サポーター派遣事業（渋谷区）', '渋谷区在住で妊娠中、または3歳未満の乳幼児を養育する家庭に、区が委託した家事サポーターが訪問し、居室の清掃・整理整頓、洗濯、食事の準備と後片付け、買い物などの日常的な家事を支援する事業です。妊娠・出産前後の家庭の家事負担を軽減することを目的としています。育児（子どもの預かり・世話）は原則この事業の対象外で、預かりが必要な場合は区の『ベビーシッター利用支援事業（一時預かり利用支援）』が別に用意されています。', '妊娠中や3歳未満のお子さんがいる渋谷区のご家庭に、家事をお手伝いするサポーターが訪問してくれる制度です。掃除・洗濯・食事の準備・買い物などをお願いできます。子どもの預かりは別の制度（ベビーシッター利用支援事業）が担当します。利用には事前の登録申請が必要です。', 'service', '渋谷区に住民登録があり、妊娠中の方、または3歳未満の乳幼児を養育している方が対象です。利用時は保護者および3歳未満の乳幼児が在宅していることが必要です。詳しい対象要件は渋谷区の公式ページでご確認ください。', '利用料は1時間あたり1,100円（税込）。減免制度として、生活保護世帯は免除、住民税非課税世帯は1時間550円（税込）に減額されます。', '妊娠中～お子さんが3歳の誕生日を迎える前日までの期間に、利用可能時間（児童1人につき通算96時間）の範囲で随時利用申請できます（詳細は公式で要確認）。', '渋谷区公式LINEアカウントを友だち登録し、申請メニューから派遣登録の申請を行い、承認通知を受けた後、承認された事業者の中から選んで予約します。サービス利用後は事業者へ直接料金を支払います（利用時はLINEでチェックイン・チェックアウト）。', '妊娠中の方は母子健康手帳の写しなど。住民税非課税世帯・生活保護世帯で減免を受ける場合は、それを証明する書類が必要となる場合があります（詳細は公式で要確認）。', TRUE, '渋谷区 子ども家庭支援センター', '03-3463-3748', NULL, 'https://www.city.shibuya.tokyo.jp/kodomo/hoiku/hoiku-service/kajisapota.html', '産前産後家事サポーター派遣事業 | 保育サービス | 渋谷区ポータル', '2026-06-24', 'high', ARRAY['applicationDeadlineText', 'requiredDocumentsText']::text[], '本情報は渋谷区公式ページ（確認日2026-06-25）に基づく概要です。対象要件・利用料・利用時間・必要書類などは変更される場合があるため、申請前に必ず渋谷区の公式ページまたは子ども家庭支援センターでご確認ください。当サイトは申請の代行や受給の保証を行うものではありません。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
