insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'nakano'), 'tokyo-nakano-prenatal-postpartum-helper', '産前産後家事・育児支援事業（中野区）', '中野区が、妊娠中または1歳未満の子がいる家庭に家事育児サポーターを派遣し、家事（食事準備・洗濯・清掃・買い物・きょうだい送迎など）と育児（授乳・おむつ替え・育児相談・沐浴補助など）を支援するヘルパー派遣型の事業です。産後ケア事業（宿泊・通所・訪問）とは別の制度です。', '赤ちゃんを迎える前後の家庭に、家事や育児を手伝うサポーター（ヘルパー）を区が派遣してくれる制度です。妊娠中から子どもが1歳になる前日まで利用でき、料金は世帯の課税状況によって異なります。申し込みは区内のすこやか福祉センターの窓口か電子申請でできるとされています。', 'service', '中野区に住所があり、妊娠中またはお子さんが1歳未満の家庭が対象となる可能性があります。妊娠届出以降に申請できるとされています。詳しい対象要件は中野区の公式ページで確認してください。', '利用できる時間数は40時間（区への利用申請時に3歳未満の兄姉がいる世帯は80時間）とされ、対象期間は妊娠中から対象児が1歳になる前日までと案内されています。利用料は住民税課税世帯で1時間につき800円、非課税世帯・生活保護世帯は無料とされています（公式で要確認）。', '対象期間は妊娠中から対象のお子さんが1歳になる前日までとされています。明確な申請締切は公式ページに明示されていないため、利用を希望する場合は早めに公式ページや窓口で確認してください。', '各すこやか福祉センター（中部・北部・南部・鷺宮）の窓口での申請、または電子申請フォームから申し込む方法があると公式ページに記載されています。具体的な手続き・受付状況は中野区の公式ページや地域包括ケア推進課でご確認ください。', '必要書類の詳細は公式ページに明記されていません。申請にあたっての持ち物・書類は中野区の公式ページまたは地域包括ケア推進課にご確認ください。', TRUE, '中野区 地域支えあい推進部 地域包括ケア推進課', '03-3228-8809', 'https://www.city.tokyo-nakano.lg.jp/kosodate/kosodatesite_ohirune/nenreibetsu/syussan/sangoshien/sangokaji.html', 'https://www.city.tokyo-nakano.lg.jp/kosodate/kosodatesite_ohirune/nenreibetsu/syussan/sangoshien/sangokaji.html', '産前産後家事・育児支援事業 | 中野区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText', 'targetPeople']::text[], '本ページは中野区の公式情報をもとにした概要です。対象要件・利用時間・料金・申請方法は変更される場合があるため、最新の正確な内容は必ず中野区の公式ページまたは地域包括ケア推進課でご確認ください。当サイトが申請を代わりに行うすることはありません。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
