insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'suginami'), 'tokyo-suginami-prenatal-postpartum-helper', '産前・産後支援ヘルパー（杉並区）', '杉並区が、妊娠中または1歳未満の子を養育する家庭にヘルパーを派遣し、家事（食事支度・洗濯・掃除・買い物など）と育児（対象児や上の子の世話）を支援する区独自の事業です。出産前後の家庭の負担軽減を目的としています。', '妊娠中や赤ちゃんが生まれて間もない時期に、家事や育児を手伝うヘルパーさんを自宅に派遣してもらえる杉並区の制度です。ごはんの支度・洗濯・掃除・買い物のほか、赤ちゃんや上の子のお世話もお願いできます。利用には事前の申請が必要で、申請から利用開始まで2週間前後かかります。', 'service', '杉並区内在住の妊婦、または1歳未満の子を養育する保護者が対象となる可能性があります。対象の詳細・要件は公式ページでご確認ください。', 'ヘルパー派遣による家事・育児支援サービス。利用料は、生活保護世帯・住民税非課税世帯は無料、その他は1時間あたり1,000円とされています（杉並子育て応援券での支払い可、交通費は利用者負担）。料金は変更される可能性があるため公式でご確認ください。', '妊娠がわかった時点から産前分、出産予定日のおおむね2カ月前から産後分の申請ができるとされています。詳細は公式でご確認ください。', '電子申請、来所（区役所東棟3階）、郵送のいずれかで申請します。申請から利用開始まで2週間前後かかるとされています。詳細・最新の手続きは公式ページでご確認ください。', '申請書のほか、妊娠中は母子健康手帳表紙のコピー、無料対象となる場合は住民税非課税証明書または生活保護受給証明書のコピーなどが必要とされています。必要書類は公式でご確認ください。', TRUE, '杉並区 地域子育て支援課 子育て支援係', '03-5307-0345', 'https://www.city.suginami.tokyo.jp/guide/kosodate/ninshin/1004681.html', 'https://www.city.suginami.tokyo.jp/guide/kosodate/ninshin/1004681.html', '産前・産後支援ヘルパー｜杉並区公式ホームページ', '2026-06-24', 'high', ARRAY['benefitAmountText', 'targetPeople', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本情報は2026-06-25時点で杉並区公式ホームページを基に整理した参考情報です。対象・利用料・利用時間・回数などの制度内容は変更される場合があり、利用の可否は区の審査・状況によります。最新かつ正確な情報は必ず公式ページや問い合わせ先でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
