insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'toshima'), 'tokyo-toshima-prenatal-postpartum-helper', 'としまいっしょに子育て 育児支援ヘルパー事業（豊島区）', '豊島区の独自事業。妊娠中から産後（おおむね2歳未満の子がいる家庭）に支援員（ヘルパー）を派遣し、授乳・沐浴・おむつ交換・きょうだいの世話・健診付き添いなどの育児や、洗濯・掃除・簡易な調理といった家事を手伝う制度です。事前登録のうえ、原則利用日の1週間前までに子ども家庭支援センターへ予約して利用します。母子の心身ケアを行う産後ケア事業とは別の事業です。', '豊島区にお住まいで、妊娠中または2歳未満のお子さんがいる家庭に、ヘルパーが来て育児（授乳・沐浴・おむつ替え・上の子の世話など）や家事（洗濯・掃除・簡単な調理）を手伝ってくれる区の制度です。1回の妊娠につき70時間まで（双子以上は160時間まで）、1回2〜4時間利用でき、料金は1時間900円（多胎児1,350円）。非課税世帯などは減免があります。利用には事前登録と、原則1週間前までの予約が必要です。', 'service', '公式サイトによると、豊島区内在住で2歳未満の子どもがいる家庭が対象となる可能性があります。出産前（妊娠中）からも利用できるとされています。最新の対象要件は必ず豊島区公式ページでご確認ください。', '公式サイトによると、利用料は1時間あたり900円（多胎児の場合は1,350円）とされています。非課税世帯等には減免制度があり、申請が必要です。料金は変更される可能性があるため、最新の金額は公式ページでご確認ください。', '公式サイトによると、原則として利用日の1週間前までに予約が必要です（休日が連続する場合は1週間以上前）。', '事前登録が必要です。公式サイトによると、原則として利用日の1週間前までに、東部子ども家庭支援センター（電話03-5980-5275）または西部子ども家庭支援センター（電話03-5966-3131）へ電話で予約します。休日が連続する場合は1週間以上前の予約が必要となることがあります。詳しい手続き・申請書は豊島区公式ページでご確認ください。', '事前登録および利用申請が必要とされていますが、必要書類の詳細は公式ページ・各センターでご確認ください。減免を希望する場合は別途申請が必要です。', FALSE, '東部子ども家庭支援センター／西部子ども家庭支援センター', '03-5980-5275（東部）／03-5966-3131（西部）', 'https://www.city.toshima.lg.jp/265/kosodate/kosodate/shiencenter/022315.html', 'https://www.city.toshima.lg.jp/265/kosodate/kosodate/shiencenter/022315.html', 'としまいっしょに子育て 育児支援ヘルパー事業 - 豊島区', '2026-06-24', 'high', ARRAY['requiredDocumentsText', 'onlineApplicationAvailable']::text[], '本情報は豊島区公式ページ（最終更新2026-05-08）の確認に基づく概要です。対象・利用時間・回数・料金・減免・必要書類などは変更される場合があります。利用にあたっては必ず豊島区公式ページおよび子ども家庭支援センターで最新情報をご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
