insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'kita'), 'tokyo-kita-prenatal-postpartum-helper', '安心ママパパヘルパー事業（北区）', '東京都北区が実施する区独自のヘルパー派遣事業。妊娠中（産前1か月前）から子が2歳になる年度まで、家庭にベビーシッターや産後ドゥーラ（専門支援員）が訪問し、家事（食事の準備・後片付け、洗濯、掃除、買い物）や育児（育児相談・見守り、ミルク作り、おむつ交換、沐浴介助など）を支援することで、出産・子育ての不安や負担の軽減を図る制度です。母子の心身をケアする「産後ケア事業」とは別の制度です。', '赤ちゃんが生まれる前後の家庭に、家事や育児を手伝うヘルパーさんが訪問してくれる北区の制度です。料理・洗濯・掃除・買い物や、ミルク・おむつ替え・沐浴のお手伝いなどをお願いできます。子ども1人につき2時間までは無料の枠があり、その後は世帯の課税状況に応じた利用料がかかります。利用には事前の登録が必要で、詳しい対象・料金・利用できる時間は公式ページや子ども家庭支援センターでご確認ください。', 'service', '北区内在住で、産前1か月前から2歳（3歳になる前日）までの育児を行っている家庭が対象です。保護者と対象のお子さんが在宅しているときに利用できると公式で案内されています。詳細・最新の対象要件は公式ページでご確認ください。', 'ヘルパー派遣による家事・育児支援サービス（現物給付）。公式では子ども1人につき2時間までは無料、超過分は世帯の課税状況に応じて1時間あたり500円〜1,000円と案内されています。最新の料金・利用上限時間は公式ページでご確認ください。', '通年で利用登録を受け付けていると考えられます。利用にあたっては、登録後に利用希望日の3営業日前までに派遣事業者へ予約を申し込む必要があると公式で案内されています。最新の受付時期・期限は公式ページでご確認ください。', '事前の利用登録が必要です。公式案内では、郵送・窓口・電子申請（LoGoフォーム）のいずれかで利用登録申請書を提出し、登録後に利用希望日の3営業日前までに派遣事業者へ予約を申し込む流れです。申込方法・受付窓口の詳細は公式ページおよび子ども家庭支援センター（03-6903-0511）でご確認ください。', '利用登録申請書のほか、母子健康手帳の写しなどが必要となる場合があります。非課税世帯や生活保護世帯は課税状況を確認できる書類が求められる場合があります。必要書類の詳細は公式ページでご確認ください。', TRUE, '北区 子ども家庭支援センター', '03-6903-0511', 'https://www.city.kita.lg.jp/children-edu/childcare/1002833/1002855/1003940.html', 'https://www.city.kita.lg.jp/children-edu/childcare/1002833/1002855/1003940.html', '安心ママパパヘルパー事業｜東京都北区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'targetPeople', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本情報は北区公式ページ（更新日2025年10月3日・確認日2026-06-25）に基づく概要です。対象要件・利用料金・利用できる時間や回数の上限・申込手続きは変更される場合があり、世帯や状況により異なります。利用の可否や最新の詳細は必ず北区公式ページまたは子ども家庭支援センターにご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
