insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot prenatal-postpartum-helper import', '{"slug":"tokyo-kita-prenatal-postpartum-helper","status":"published","title":"安心ママパパヘルパー事業（北区）","officialUrl":"https://www.city.kita.lg.jp/children-edu/childcare/1002833/1002855/1003940.html","topic":"prenatal-postpartum-helper"}'::jsonb, 'pilot:tokyo-kita-prenatal-postpartum-helper:dG9reW8ta2l0YS1wcmVuYXRhbC1wb3N0cGFydHVt' from public.support_programs sp where sp.slug='tokyo-kita-prenatal-postpartum-helper' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'arakawa'), 'tokyo-arakawa-prenatal-postpartum-helper', 'ツインズサポート事業（多胎児家庭 産前産後支援ヘルパー派遣）', '荒川区が多胎児（双子・三つ子等）を妊娠・養育する家庭にヘルパーを派遣し、家事（食事の支度・洗濯・居室の清掃・買い物・健診の付添い等）や育児（沐浴・授乳・おむつ交換の補助等）を支援する区独自のヘルパー派遣事業です。対象は多胎児家庭に限定される点に注意してください。一般の産前産後家庭向けには、別途「産後支援ボランティア派遣事業」や「荒川区産後ケア事業」があります。詳細・最新の対象や利用料は荒川区公式ページでご確認ください。', '双子や三つ子など多胎児を妊娠中・子育て中の荒川区の家庭に、ヘルパーが来て家事や赤ちゃんのお世話を手伝ってくれる区の制度です。利用には申請が必要で、1時間あたりの自己負担があります（非課税・生活保護世帯は軽減・免除の場合あり）。一般の産前産後家庭は対象外のことが多いため、まず公式ページで対象を確認してください。', 'service', '荒川区在住で、母子健康手帳を取得し多胎児を出産予定の方、または多胎児を養育する家庭が対象となる可能性があります（対象は多胎児家庭に限定。一般の産前産後家庭は対象外の可能性が高い）。具体的な対象範囲・対象年齢は荒川区公式で確認してください。', '利用料はヘルパー1人につき1時間あたり300円程度とされます（住民税非課税世帯は半額、生活保護世帯は免除となる可能性）。金額・減免の詳細は公式で確認してください。', '通年で申請を受け付けているとみられます。詳細は公式でご確認ください。', '申請は窓口・郵送、または電子申請（Logoフォーム等）で受け付けているとされます。最新の申請方法・必要書類は荒川区公式ページで確認してください。', '母子健康手帳、所定の申請書など。必要書類の詳細は公式ページ・窓口で確認してください。', TRUE, '荒川区 子ども家庭部 子ども・若者課', '03-3802-3111', 'https://www.city.arakawa.tokyo.jp/a035/kosodate/kosodateshien/twins_helper_r7.html', 'https://www.city.arakawa.tokyo.jp/a035/kosodate/kosodateshien/twins_helper_r7.html', 'ツインズサポート事業（多胎児家庭産前産後支援ヘルパー派遣）／荒川区公式サイト', '2026-06-24', 'medium', ARRAY['targetPeople', 'benefitAmountText', 'benefitType', 'applicationDeadlineText', 'onlineApplicationAvailable', 'requiredDocumentsText']::text[], '本情報は荒川区公式サイトの記載と検索結果に基づく概要です。対象・利用料・利用時間や回数は変更される場合があり、また対象が多胎児家庭に限定されます。最新かつ正確な情報は必ず荒川区公式ページおよび担当窓口でご確認ください。当サイトは申請の代行・受給の保証を行うものではありません。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
