insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'itabashi'), 'tokyo-itabashi-prenatal-postpartum-helper', '板橋区 育児支援ヘルパー派遣事業', '板橋区が委託する事業者のヘルパーが自宅を訪問し、妊娠中〜3歳になる前の児童がいる世帯の家事・育児を支援する区の事業。食事の支度・買い物・洗濯・掃除などの家事や、沐浴補助・育児相談・健診の付き添い・乳幼児の見守りなどを支援する可能性がある。利用料や時間は条件により異なるため、公式で確認が必要。', '板橋区の事業です。妊娠中から3歳になる前のお子さんがいるご家庭に、区から委託を受けたヘルパーが訪問し、食事づくり・買い物・洗濯・掃除などの家事や、沐浴の手伝い・育児の相談・健診の付き添い・お子さんの見守りなどをお手伝いする場合があります。利用料や利用できる時間・回数には条件があり、住民税非課税世帯などには利用料の減免制度があるとされています。対象かどうかや料金、申し込み方法は、必ず板橋区の公式ページでご確認ください。', 'service', '板橋区に住民登録があり、妊娠中の保護者（母子健康手帳取得後）がいる世帯、または3歳の誕生日前日までの児童がいる世帯が対象となる可能性がある。詳しい要件は公式ページで確認すること。', '利用料は時間帯により1時間につき800円または900円とされる場合がある（住民税非課税世帯等を対象とした減免制度があるとされる）。なお令和7年4月から、妊娠中〜1歳誕生日前日までの利用について初回から一定時間まで無料とされる場合がある。金額は変更の可能性があるため公式で確認すること。', '初回申請は利用希望日の5日前（土日祝を除く）、2回目以降は3日前までとされる場合がある。公式で確認すること。', 'オンライン申請フォーム（QRコード）からの申し込みとなる可能性がある。初回は利用希望日の5日前（土日祝除く）、2回目以降は3日前までの申請とされる場合がある。詳細・最新の手続きは公式ページや委託事業者（株式会社パソナライフケア）に確認すること。', '減免を希望する場合など、条件によって非課税証明書等の提出が求められる可能性がある。詳細は公式で確認すること。', TRUE, '板橋区 子ども家庭総合支援センター支援課 ／ 委託事業者 株式会社パソナライフケア', '03-5944-2371（子ども家庭総合支援センター支援課）／ 0120-022-177（株式会社パソナライフケア）', 'https://www.city.itabashi.tokyo.jp/kosodate/ninshin/ninshin/1004071.html', 'https://www.city.itabashi.tokyo.jp/kosodate/ninshin/ninshin/1004071.html', '育児支援ヘルパー派遣事業｜板橋区公式ホームページ', '2026-06-24', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText', '利用時間/回数/上限時間', '減免制度・無料利用枠の詳細・対象', '産後ケア事業・産後ドゥーラ事業との利用調整']::text[], '本要約は板橋区公式ページをもとにした参考情報です。対象要件・利用料・利用時間/回数・申込方法は変更される場合があり、個別の利用可否は区の判断によります。必ず公式ページおよび委託事業者で最新情報をご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
