insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot prenatal-postpartum-helper import', '{"slug":"tokyo-itabashi-prenatal-postpartum-helper","status":"published","title":"板橋区 育児支援ヘルパー派遣事業","officialUrl":"https://www.city.itabashi.tokyo.jp/kosodate/ninshin/ninshin/1004071.html","topic":"prenatal-postpartum-helper"}'::jsonb, 'pilot:tokyo-itabashi-prenatal-postpartum-helper:dG9reW8taXRhYmFzaGktcHJlbmF0YWwtcG9zdHBh' from public.support_programs sp where sp.slug='tokyo-itabashi-prenatal-postpartum-helper' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'nerima'), 'tokyo-nerima-prenatal-postpartum-helper', '練馬区 育児支援ヘルパー事業', '妊娠中から子どもが2歳になる月の末日までの家庭に、家事支援を行うヘルパーを派遣する練馬区独自の事業です。食事の支度・洗濯・居室の掃除・買い物・赤ちゃんの沐浴の補助・乳幼児健診等の付き添いなどを依頼でき、産前産後の体調不良などで支援が必要な家庭を助けます。産後ケア事業（宿泊・通所・訪問による母子の心身ケア）とは別の制度です。対象・利用時間・利用料は条件により異なるため、必ず練馬区公式の案内で確認してください。', '練馬区では、妊娠中から子どもが2歳になるまでの家庭に、家事や育児を手伝うヘルパーを派遣しています。食事づくり・洗濯・掃除・買い物・赤ちゃんの沐浴の手伝い・健診の付き添いなどを頼めます。利用には事前の申請（電子申請または郵送）が必要で、料金は条件によって変わります（無料になる場合もあります）。詳しくは区の公式ページで確認してください。', 'service', '妊娠中から子どもが満2歳に達する月の末日までの保護者が対象となる可能性があります。対象範囲の詳細は練馬区公式で確認してください。', '利用料は原則1時間1,000円（税込）。低体重児を出産した方・20歳未満で出産した方・切迫早産等の診断を受けた方は1時間500円、多胎児家庭は1時間300円、住民税非課税世帯・生活保護受給世帯は無料と案内されています（条件により異なるため公式で確認）。', '公式ページに明確な申請期限の記載は確認できませんでした。利用を希望する場合は早めに練馬区公式へ確認してください。', '在宅育児支援担当課（子育て事業係）へ利用申請書を電子申請（LoGoフォーム）または郵送で提出し、承認後に区の事業者リストから事業者を選び直接申し込む流れと案内されています。最新の手続きは練馬区公式で確認してください。', '利用申請書（練馬区公式ページから入手）。状況により出産・妊娠の状況を確認できる書類等が必要となる場合があります。詳細は公式で確認してください。', TRUE, '練馬区 こども家庭部 在宅育児支援担当課 子育て事業係', '03-3993-1052', 'https://www.city.nerima.tokyo.jp/kosodatekyoiku/kodomo/sodan/kodomokateicenter/helper.html', 'https://www.city.nerima.tokyo.jp/kosodatekyoiku/kodomo/sodan/kodomokateicenter/helper.html', '育児支援ヘルパー：練馬区公式ホームページ', '2026-06-24', 'high', ARRAY['targetPeople', 'benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText', 'contactPhone']::text[], '本情報は練馬区公式ページ（最終更新2026-04-01時点）に基づく概要です。対象・利用時間・料金等は変更される場合があり、条件により異なります。利用前に必ず練馬区公式ページおよび担当課でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
