insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'adachi'), 'tokyo-adachi-prenatal-postpartum-helper', '足立区 産前・産後家事支援事業', '足立区が、出産予定日の6週間前から出産後3か月までの妊産婦がいる区内在住の家庭に、委託事業者の家事支援ヘルパーを派遣し、食事の準備・後片付け、洗濯、居室の清掃・整理整頓、生活必需品の買い物などの家事を補助する区独自事業です。対象となる可能性や利用料・利用回数などの詳細は足立区公式でご確認ください。', '妊娠中から産後3か月までの間、家事をする人がヘルパーとして家庭に来て、料理・洗濯・掃除・買い物などを手伝ってくれる足立区の制度です。利用するには事前の申し込みが必要で、利用料がかかります。詳しい条件や料金は足立区の公式ページで確認してください。', 'service', '区内在住で、出産予定日の6週間前から出産後3か月までの妊産婦がいる家庭が対象となる可能性があります。足立区に住民票があることなどの条件は公式で確認してください。', '利用料(自己負担)は時間帯・曜日により異なります。公式案内では平日午前8時〜午後6時が最初の1時間500円・以降30分ごと250円、平日夜間(午後6時〜8時)・土日祝が最初の1時間800円・以降400円(いずれも別途実費)と案内されていますが、金額は変動の可能性があるため足立区公式で最新情報を確認してください。', '利用開始日の7日前までに申込書の提出が必要と案内されています(公式で要確認)。', '委託事業者に連絡して利用希望を伝え、訪問による事前確認を経たうえで、利用開始日の7日前までに利用申込書を提出する流れと案内されています。最新の手順は足立区公式でご確認ください。', '産前・産後家事支援事業利用申込書、母子健康手帳など(詳細は公式で確認)。', FALSE, '足立区 教育委員会事務局子ども家庭部子ども政策課 子育て応援係', '03-3880-0719', NULL, 'https://www.city.adachi.tokyo.jp/kodomokate/k-kyoiku/kosodate/homehelp-jigyou.html', '産前・産後家事支援事業｜足立区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本情報は足立区公式サイトの掲載内容に基づく概要です。対象要件・利用料・利用回数や時間・申込方法は変更される場合があり、個別の対象可否は審査・確認が必要です。必ず足立区公式ページおよび担当課でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
