insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'katsushika'), 'tokyo-katsushika-prenatal-postpartum-helper', '子育て家庭等家事サポーター派遣事業（葛飾区）', '葛飾区が、区内在住の妊婦または3歳未満の子どもを養育している家庭を対象に、区が利用料を補助することで、協定を締結した民間事業者の家事サービス（家事サポーター派遣）を負担なく利用できる事業です。対象となる場合は無料で利用できる可能性があります（交通費等は利用者負担）。対象・詳細は公式サイトでご確認ください。', '妊娠中や小さなお子さん（3歳未満）を育てている葛飾区の家庭に、家事を手伝う「家事サポーター」を派遣してくれる制度です。食事の支度・洗濯・掃除・買い物・健診の付き添いなどをお願いでき、区が利用料を補助するため、対象となる場合は無料で利用できる可能性があります（交通費などは自己負担）。', 'service', '葛飾区在住で、妊婦の方（妊娠届提出後）、または3歳未満の子どもを養育している家庭が対象となる可能性があります。妊婦については単胎・多胎いずれも対象とされています。利用可能期間は子どもが3歳の誕生日を迎える前日までとされています。具体的な対象要件は公式サイトでご確認ください。', '区が利用料を補助することで、対象となる場合は無料で利用できる可能性があります。ただし交通費等は利用者負担とされています。利用時間は妊婦または3歳未満の子ども1人当たり96時間とされています（詳細は公式サイトでご確認ください）。', '公式ページに明確な申請期限の記載は確認できませんでした。妊婦の方は妊娠届提出後の申請が必要とされています。利用可能期間は子どもが3歳の誕生日を迎える前日までです。', '電子申請システムによる申請、または「家事サポーター利用申請書」を葛飾区役所4階の子育て応援課へ持参・郵送することで申請できるとされています。詳細・最新の手続きは公式サイトでご確認ください。', '「家事サポーター利用申請書」（公式サイトからダウンロード可）。必要書類の詳細は公式サイトでご確認ください。', TRUE, '葛飾区 子育て応援課（子育て家庭等家事サポーター派遣事業）', '0120-215-214（事業専用・土日祝・年末年始を除く8:30〜17:15）', 'https://www.city.katsushika.lg.jp/kosodate/1000056/1002333/1025713.html', 'https://www.city.katsushika.lg.jp/kosodate/1000056/1002333/1025713.html', '子育て家庭等家事サポーター派遣事業｜葛飾区公式サイト', '2026-06-24', 'high', ARRAY['applicationDeadlineText', 'requiredDocumentsText']::text[], '本情報は葛飾区公式サイト（確認日2026-06-25）に基づく概要です。対象要件・利用時間・利用料・必要書類は変更される場合があります。申請にあたっては必ず公式サイトおよび区の窓口で最新情報をご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
