insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'edogawa'), 'tokyo-edogawa-prenatal-postpartum-helper', 'えどがわママパパ応援隊（家事・育児支援事業）', '江戸川区が行う家事・育児支援事業。妊娠中または3歳未満の子どもがいる家庭にヘルパーを派遣し、食事の支度・片付け、掃除、育児の補助、健診や買い物等の外出同行などを支援します。子どもの預かり（ベビーシッター）は行いません。母子の心身ケアを行う産後ケア事業とは別の制度です。', '妊娠中の方や3歳未満の子どもがいる家庭に、家事や育児を手伝うヘルパーを派遣してくれる江戸川区の制度です。食事づくり・掃除・育児の補助・健診や買い物への付き添いなどをお願いできます（子どもだけを預かるベビーシッターはありません）。利用料は1時間500円で、0歳児を育てる家庭は一定時間まで無料です。申し込みは委託事業者のホームページから行います。', 'service', '江戸川区内に居住し、妊娠中の方または3歳未満の子どもがいる家庭が対象となる可能性があります。詳しい対象要件は公式ページで確認してください。', '利用料は1時間あたり500円（公式記載。一部減額制度あり）。0歳児（妊娠期を含む）を養育する家庭は1人につき14時間まで無料とされています。対象児1人あたり年間96時間まで（双子は240時間、1日2時間以上）利用できるとされています。利用時間・回数・料金は変更される場合があるため公式ページで確認してください。', '明確な締切の記載はありませんが、基本的に利用希望日の1週間〜10日程度前までの申請が推奨されています。', '委託事業者（株式会社パソナライフケア）のホームページから直接オンラインで申し込む方式です。基本的には利用希望日の1週間〜10日程度前の申請が推奨されています（急を要する場合は相談可とされています）。詳細は公式ページで確認してください。', '妊娠中の方は母子健康手帳の表紙等の写しが必要とされています。詳細は公式ページ・委託事業者で確認してください。', TRUE, '江戸川区児童相談所「はあとポート」相談課事業係 ／ 委託事業者 株式会社パソナライフケア', '0120-060-366（委託事業者）／ 03-3652-1151（江戸川区代表）', 'https://www.city.edogawa.tokyo.jp/e077/kosodate/kosodate/mamapapa_ouentai.html', 'https://www.city.edogawa.tokyo.jp/e077/kosodate/kosodate/mamapapa_ouentai.html', '家事・育児支援事業「えどがわママパパ応援隊」 江戸川区ホームページ', '2026-06-24', 'high', ARRAY['targetPeople', 'benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '対象要件・利用料・利用時間/回数・必要書類などは変更される場合があります。申請前に必ず江戸川区公式ページおよび委託事業者で最新情報をご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
