insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.chiyoda.lg.jp/koho/kosodate/kosodate/ninshin/homon.html', '敵対的検証を実施。program.officialUrl（https://www.city.chiyoda.lg.jp/koho/kosodate/kosodate/ninshin/homon.html）をWebFetchで再取得し全7項目を照合。(a)到達=更新日2026-04-06で現行・受付終了でない。(b)許可ホスト=www.city.chiyoda.lg.jp（.lg.jp）で合致、FAQ専用ドメインでない。(c)千代田区自身の「育児支援訪問事業」ページで当該区の家事・育児ヘルパー派遣そのもの。(d)古い年度でない。(e)重要=産後ケア事業（母子の心身ケアの宿泊/通所/訪問）と取り違えていない。本ページは支援員が家庭訪問し授乳手伝い・食事介助・沐浴補助・おむつ替え・送迎付き添い等を行う家事育児ヘルパー派遣事業であることを公式本文で確認。(f)対象の一部を全体と書いていない（妊産婦生後1歳未満/義務教育終了前児童・一時的育児困難認定・他に支援者なし、を「可能性」「公式で確認」で概括）。(g)複数制度を混在させていない（単一事業）。(h)区差のある対象/利用料/時間/必要書類は概' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='chiyoda' and t.slug='prenatal-postpartum-helper' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.chuo.lg.jp/a0025/kosodate/shussan/shussanshien/ikujisien.html', '敵対的検証の結果、一次調査は妥当と確認。officialUrl(https://www.city.chuo.lg.jp/a0025/kosodate/shussan/shussanshien/ikujisien.html)をWebFetchで取得し以下を確認(2026-06-25時点)。(a)到達OK。(b)ホストwww.city.chuo.lg.jpは許可(.lg.jp/city.*)。(c)中央区公式の「育児支援ヘルパー」ページ＝区が契約事業者からヘルパーを家庭へ派遣し家事・育児を支援する区独自事業で本タスクの対象に該当。(d)掲載日2026-04-13・令和8年度(2026年度)情報・受付終了の記載なし＝現行。(e)産後ケア事業(母子の心身ケア・宿泊等)とは別物であることをページ本文が明示しており取り違えなし。(f)対象は「出産前(母子健康手帳交付時)〜出産後6カ月まで」で一次調査と一致、一部を全体と誤記なし。(g)単一制度のみで複数制度の混在なし。(h)区差のある対象・利用料・時間・必要書類はuncertainFieldsに列挙し非断定+「公式で確認」表現で概括。利用回数15回' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='chuo' and t.slug='prenatal-postpartum-helper' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.minato.tokyo.jp/kosodatesien/kenko/ninshin/shussan/mama-support.html', 'WebFetchで官公署許可ホスト(www.city.minato.tokyo.jp＝city.*/.tokyo.jp)の当該ページに到達し検証。(a)到達OK。(b)港区公式の許可ホスト一致(FAQ専用ドメインではない)。(c)港区「産前産後家事・育児支援サービス」＝ホームヘルパー/産後ドゥーラが自宅訪問する家事・育児支援ヘルパー派遣の当該区ページであることを確認。(d)最終更新2026-05-28で現行・受付終了でない。(e)母子の心身ケアを行う産後ケア事業(宿泊/通所/訪問)ではなく、家事・育児支援の訪問派遣ページであり取り違えなし。(f)対象は妊娠中又は出産後の家庭・子が3歳の前日までを概括し非断定＋uncertainFields化。(g)単一制度のみで複数制度の混在なし。(h)対象・利用料・利用時間など区差/世帯差のある項目は概括し「公式で確認」を付し断定回避。支援内容(家事支援:食事準備・掃除・洗濯・買い物・検診付添、産後ドゥーラ:沐浴援助・授乳見守り・育児相談・きょうだい送迎)、料金(単胎で家事支援2h1,500円〜4h3,000円・ドゥーラ2h2,000円〜4h4,00' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='minato' and t.slug='prenatal-postpartum-helper' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.shinjuku.lg.jp/kodomo/file03_02_00001.html', '敵対的検証実施。program.officialUrl（https://www.city.shinjuku.lg.jp/kodomo/file03_02_00001.html）をWebFetchで再取得し、一次調査の主張を全項目突合した。(a)到達=200・本文取得可。(b)ホスト=www.city.shinjuku.lg.jp＝.lg.jp許可ホスト一致。(c)当該区ページ=「産前産後支援事業」、訪問型の家事・育児支援ヘルパー（又は産後ドゥーラ）派遣事業であることを本文で確認。(d)現行性=最終更新2026-04-01・令和8年度版・受付終了表示なし。(e)産後ケア事業（母子の心身ケア：宿泊/通所/訪問）との取り違えなし＝本文は訪問型の家事育児支援が中心で心身ケア専門ではないと確認。(f)対象=妊婦/1歳未満児養育/多子家庭/多胎児等を「対象となる可能性」と概括し全体断定を回避。(g)複数制度の混在なし。(h)FORBIDDEN/断定なし、区差のある対象・利用料・時間は概括＋「公式で確認」付記。料金（産後ドゥーラ1時間1,500円・ヘルパー1時間1,000円、減額免除あり）、申請方法' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='shinjuku' and t.slug='prenatal-postpartum-helper' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.bunkyo.lg.jp/b022/p001690.html', 'WebFetchで文京区公式 https://www.city.bunkyo.lg.jp/b022/p001690.html を検証。(a)到達OK (b)許可ホスト city.bunkyo.lg.jp（.lg.jp）一致 (c)文京区の家事・育児ヘルパー派遣「おうち家事・育児サポート事業」の当該区ページ＝サポート券で区指定の民間事業者の家事・育児サポートを利用する在宅支援事業であることを公式で確認 (d)更新日2026-04-06で現行・受付終了でない (e)産後ケア事業（母体・新生児の宿泊/通所/訪問ケア）ではなくヘルパー派遣事業であることを公式記載で確認＝取り違えなし (f)対象（区内在住の妊婦または満3歳未満乳幼児がいる世帯、多胎児は対象外）を全体として正しく記載 (g)複数制度の混在なし (h)利用料1,000円/時・非課税半額助成・必要書類（妊娠中は母子手帳表紙コピー）・申請方法（電子推奨/郵送/窓口）・問い合わせ（こども未来部こども若者支援課 03-5803-1288）すべて公式と一致。利用枠は公式では「初回～0歳児券40枚・1・2歳児券20枚、追加申請で最大96時間分、' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='bunkyo' and t.slug='prenatal-postpartum-helper' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.taito.lg.jp/kosodatekyouiku/kosodate/nenrei/ninshinki/soudan_shien/helper_ippan.html', '敵対的検証実施（2026-06-25）。program.officialUrl をWebFetchで再取得し、一次調査の妥当性を点検。(a)到達OK (b)ホスト www.city.taito.lg.jp は許可ホスト(.lg.jp/city.*)に一致 (c)台東区の「産前産後支援ヘルパー\"あったかハンド\"【一般向け（多胎を除く）】」＝家事・育児支援ヘルパー派遣そのものの当該区ページであることを確認 (d)更新日2026-04-16・事業者追加が令和8年1月5日までの記載でアクティブ、受付終了/古い年度ではない (e)産後ケア事業（母子の心身ケアの宿泊/通所/訪問）ではなく、出産・育児の負担軽減のため家事・育児を支援する生活支援型ヘルパー派遣であることを確認＝取り違えなし (f)対象は一般向け（多胎を除く）であり一部を全体と書いていない (g)複数制度の混在なし (h)断定回避・概括+「公式で確認」を維持。利用料は1時間1人あたり300円（減免あり）、上限は各期間（母子手帳取得〜1歳未満/1〜2歳未満/2〜3歳未満）ごとに96時間・1日最大4時間。申請はmila-eオンライン申請' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='taito' and t.slug='prenatal-postpartum-helper' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.sumida.lg.jp/kosodate_kyouiku/kosodate_site/sodan/kajiikuji.html', '検証完了(2026-06-25)。program.officialUrl(https://www.city.sumida.lg.jp/kosodate_kyouiku/kosodate_site/sodan/kajiikuji.html)をWebFetchで取得し全チェック通過。(a)到達OK。(b)許可ホスト=www.city.sumida.lg.jp(city.*/.lg.jp)で合致。(c)墨田区公式「家事・育児サポーター事業」=当該区のヘルパー派遣事業ページ本体。(d)2026-03-01更新・令和7年9月18日以降の利用時間上限を明記=現行・受付終了でない。(e)重要: 産後ケア事業(母子の心身ケアの宿泊/通所/訪問)との取り違えなし。本ページは自宅へサポーターを派遣する家事・育児支援のホームヘルパー派遣事業であることを公式本文で確認。(f)対象(妊娠中の方+0〜2歳児養育家庭)は全体像と一致、一部を全体と誤記していない。(g)複数制度の混在なし(単一事業)。(h)断定回避・区差のある利用料/利用時間は概括し「公式で確認」を明記。原一次調査の記載内容(対象・支援内容・申請方法' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='sumida' and t.slug='prenatal-postpartum-helper' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.koto.lg.jp/281012/kajiikuji-kateihoumon.html', 'WebFetchで江東区公式(city.koto.lg.jp=.lg.jp許可ホスト)の「こうとう家事・育児サポート事業」ページを実検証(更新日2026-06-04、受付終了表記なし=現行)。本ページは家事・育児支援ヘルパー(訪問支援者)派遣事業であり、母子の心身ケアを行う産後ケア事業(宿泊/通所/訪問)とは別制度であることをページ内容で確認(掃除・買い物・洗濯・調理等の家事支援＋授乳見守り・沐浴等の育児支援)。対象=区内在住で3歳未満の子を養育する家庭、利用料1時間500円、訪問最低2時間以上(1時間単位)、原則電子申請(窓口・郵送可)、所管=こども家庭支援課こども家庭係(03-3647-9230)、産前(妊娠中)は出生前申請不可で産後(出生届出後)に申請、いずれも一致。1点だけ精緻化: 月間上限は公式では年齢別かつきょうだい構成別の幅(0歳20〜180時間/1歳20〜40時間/2歳20時間)で示されており、一次調査の「0歳最大180h/1歳40h/2歳20h」は上限値のみの記載だが「年齢別上限あり」「利用時間・回数の上限」をuncertainFieldsで既に概括・要確認扱いとして' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='koto' and t.slug='prenatal-postpartum-helper' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'http://www.city.shinagawa.tokyo.jp/PC/kodomo/kodomo-kateisoudan/hpg000023819.html', '敵対的検証実施（2026-06-25）。officialUrl（http://www.city.shinagawa.tokyo.jp/PC/kodomo/kodomo-kateisoudan/hpg000023819.html）をWebFetchで2回取得し検証した。(a)到達=OK。(b)許可ホスト=OK（www.city.shinagawa.tokyo.jp は city.* かつ .tokyo.jp の品川区公式ドメイン。FAQ専用ドメインではない）。(c)当該区のヘルパー派遣事業ページであることを確認（事業名『すこやかサポート(育児支援ヘルパー)』）。(d)受付終了・古い年度の明示なし。ただしページ最終更新日は令和4年4月1日（2022-04-01）と比較的古く、料金・日数は変更の可能性あり→uncertainFields/disclaimerで対応。(e)産後ケア事業（宿泊/通所/訪問の母子心身ケア）との取り違えなし=本ページは家事・育児支援のヘルパー派遣で別制度。(f)対象の一部を全体と書く誤りなし。(g)複数制度の混在なし（単一制度の単独ページであることを確認）。(h)断' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='shinagawa' and t.slug='prenatal-postpartum-helper' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
