insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.shibuya.tokyo.jp/kodomo/hoiku/hoiku-service/kajisapota.html', 'WebFetchで渋谷区公式ページ（city.shibuya.tokyo.jp＝許可ホスト）に到達し、一次調査を全項目検証。正式名称「産前産後家事サポーター派遣事業」、これは家事支援ヘルパーの派遣事業であり、母子の心身ケアを行う「産後ケア事業」とは別物（ページ自体が明記し、育児預かりは別の『ベビーシッター利用支援事業』へ案内＝制度混在なし）。公式記載と一致を確認: 対象＝渋谷区在住で妊娠中または3歳未満児を養育、利用料1時間1,100円（税込）・生活保護世帯免除・非課税世帯550円、上限児童1人96時間、申請は渋谷区公式LINE、問い合わせ＝子ども家庭支援センター03-3463-3748。更新日2026-04-01で受付終了の記載なし＝現行。報道の1,000円ではなく公式の1,100円が正。一次調査のbenefitAmountText/targetPeoldはむしろ公式で高確度確認できたためuncertainから除外し、公式に明記のないapplicationDeadlineText/requiredDocumentsTextのみ不確実として残置。ok=true。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='shibuya' and t.slug='prenatal-postpartum-helper' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
