insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.toshima.lg.jp/265/kosodate/kosodate/shiencenter/022315.html', '敵対的検証完了。WebFetchで program.officialUrl（https://www.city.toshima.lg.jp/265/kosodate/kosodate/shiencenter/022315.html）に到達し、一次調査の各記載を照合した。(a)到達OK。(b)ホストは www.city.toshima.lg.jp ＝ city.*＋.lg.jp で許可ホスト一致（FAQ専用ドメインではない）。(c)豊島区公式の「としまいっしょに子育て 育児支援ヘルパー事業」当該区ページ。(d)最終更新2026-05-08・受付終了/古い年度記載なし＝現行。(e)母子の心身ケアを行う産後ケア事業ではなく、家庭にヘルパー（支援員）を派遣して育児・家事を支援するヘルパー派遣事業であることをページ本文で確認（取り違えなし。researchNoteでも産後ケア事業との区別明記）。(f)対象＝区内在住・2歳未満・妊娠中可、ページ記載と一致（一部を全体と誤記なし）。(g)単一制度で複数制度の混在なし。(h)対象・料金・時間は概括＋「公式で確認」で非断定、FORBIDDEN断定なし。数値' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='toshima' and t.slug='prenatal-postpartum-helper' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.kita.lg.jp/children-edu/childcare/1002833/1002855/1003940.html', 'officialUrl（https://www.city.kita.lg.jp/children-edu/childcare/1002833/1002855/1003940.html）をWebFetchで検証（2026-06-25）。(a)到達=200で本文取得。(b)許可ホスト=www.city.kita.lg.jp（.lg.jp かつ city.* ）でFAQ専用ドメインでない。(c)当該区=東京都北区の家事・育児支援ヘルパー派遣事業『安心ママパパヘルパー事業』の公式ページ本体。(d)現行=ページ番号1003940・更新日2025年10月3日と明記され受付終了でない。(e)産後ケアとの区別=公式本文は『家庭にヘルパーが訪問して、家事支援・育児支援を行う』訪問型の家事育児サポートで、母子の心身ケアを行う産後ケア事業（宿泊/通所/訪問）とは別物であることを確認。混同なし。(f)対象の部分を全体と書いていない=対象は『区内在住で産前1か月前から2歳（3歳になる前日）まで育児を行う家庭・保護者と対象児の在宅時のみ』を概括＋公式確認の留保付き。(g)複数制度の混在なし=本制度単独。(h)断定' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='kita' and t.slug='prenatal-postpartum-helper' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.arakawa.tokyo.jp/a035/kosodate/kosodateshien/twins_helper_r7.html', '敵対的検証を実施。一次調査の officialUrl (helper.html) は WebFetch で 404 を返し、許可ホスト内に到達可能な現行ページ twins_helper_r7.html（令和7年度版、令和8年度も継続）が存在することを確認したため、officialUrl・officialSourceTitle・contactUrl・evidenceUrl を twins_helper_r7.html へ是正。チェックリスト判定: (a)是正後URLは到達可。(b)許可ホスト一致。(c)荒川区独自の家事・育児ヘルパー派遣の当該ページ。(d)旧年度helper.htmlを現行ページへ是正。(e)産後ケア事業と取り違えなし。(f)多胎児家庭限定を全フィールドで明示。(g)単一制度。(h)概括＋公式で確認。公式確認事実: 利用料1時間300円(非課税半額/生活保護免除)、月〜土9:00〜17:00・1日4時間限度、申請=窓口/郵送/電子(Logoフォーム)、所管=子ども家庭部子ども・若者課(03-3802-3111内線3861・3736)。多胎児家庭限定だがテーマに合致する区独' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='arakawa' and t.slug='prenatal-postpartum-helper' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.itabashi.tokyo.jp/kosodate/ninshin/ninshin/1004071.html', '敵対的検証を実施し、一次調査の採用を支持。program.officialUrl（https://www.city.itabashi.tokyo.jp/kosodate/ninshin/ninshin/1004071.html）をWebFetchで取得し、以下を確認した（2026-06-25時点）。(a)到達=成功。(b)ホスト=city.itabashi.tokyo.jp＝板橋区公式・許可ホスト（.tokyo.jp/city.*）。FAQ専用ドメインではない。(c)当該ページのタイトルは「育児支援ヘルパー派遣事業」＝家事・育児を支援するヘルパー派遣事業そのもの。(d)古い年度・受付終了の表示なし。むしろ令和7年4月の制度変更（妊娠中〜1歳誕生日前日までの初回10時間無料枠新設、すくすくカードからの解除）が反映された現行ページ。(e)これは産後ケア事業（母子の心身ケア宿泊/通所/訪問）ではなくヘルパー派遣（家事育児支援）のページであり、取り違えなし＝一次調査が産後ケア事業・産後ドゥーラ事業と明示的に区別している点も妥当。(f)対象＝「妊娠中の保護者がいる世帯及び3歳誕生日前日までの児童' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='itabashi' and t.slug='prenatal-postpartum-helper' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.nerima.tokyo.jp/kosodatekyoiku/kodomo/sodan/kodomokateicenter/helper.html', 'WebFetchでprogram.officialUrlに到達・検証。(a)到達OK。(b)許可ホスト=city.nerima.tokyo.jp（city.* / .tokyo.jp）に一致、FAQ専用ドメインではない。(c)ページタイトル「育児支援ヘルパー」、練馬区こども家庭部 在宅育児支援担当課が所管する区独自の家事・育児支援ヘルパー派遣事業の当該区ページ。(d)最終更新2026-04-01、令和8年度の現行内容として掲載、受付終了・古い年度の表示なし。(e)産後ケア事業（母子の心身ケア＝宿泊/通所/訪問）ではなく、食事の支度・洗濯・居室の掃除・買い物・沐浴補助・乳幼児健診付添い等を行うヘルパー派遣（家事育児支援）のページであることを本文で確認＝取り違えなし。(f)対象は「妊娠中〜子が2歳になった月の末日まで」で本文一致、targetPeopleは範囲＋「公式で確認」で概括し一部を全体と書いていない。(g)単一制度のみで複数制度の混在なし。(h)利用料（原則1,000円／低体重児・若年・切迫500円／多胎300円／非課税・生保無料）、利用上限（96時間、条件で104/120時間）も' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='nerima' and t.slug='prenatal-postpartum-helper' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.adachi.tokyo.jp/kodomokate/k-kyoiku/kosodate/homehelp-jigyou.html', 'WebFetchでprogram.officialUrl(https://www.city.adachi.tokyo.jp/kodomokate/k-kyoiku/kosodate/homehelp-jigyou.html)を検証(2026-06-25)。(a)到達=200で正常表示。(b)許可ホスト=city.adachi.tokyo.jp(city.*/.tokyo.jp)に一致。FAQ専用ドメインではない。(c)当該区(足立区)の「産前・産後家事支援事業」=家事支援ヘルパー派遣そのもののページ。(d)更新日2025年4月2日で現行・受付終了でない。(e)産後ケア事業(母子の心身ケア宿泊/通所/訪問)とは別制度であり、本ページはヘルパー派遣(家事支援)を扱う。ページ上で育児支援は別事業と明記。(f)対象は出産予定日の6週間前〜出産後3か月の妊産婦がいる足立区在住世帯。(g)複数制度の混在なし。一次調査の内容(対象・支援内容=食事準備/後片付け・洗濯・居室清掃整頓・生活必需品の買い物、利用料=平日昼500円/以降30分250円・平日夜間/休日800円/以降400円、上限=1回1時間3' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='adachi' and t.slug='prenatal-postpartum-helper' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.katsushika.lg.jp/kosodate/1000056/1002333/1025713.html', '検証完了（確認日2026-06-25）。program.officialUrl をWebFetchで取得・到達確認。(a)到達OK (b)許可ホスト一致（www.city.katsushika.lg.jp＝.lg.jp/city.*）(c)葛飾区の「子育て家庭等家事サポーター派遣事業」＝家事・育児支援ヘルパー派遣そのものの当該区ページであることを確認 (d)令和8年4月7日に事業者一覧が更新され現在受付中＝古い年度/受付終了ではない (e)産後ケア事業（母子の宿泊・通所・訪問による心身ケア）ではなく、区が利用料を補助して協定民間事業者の家事サービスを無料利用できる家事サポーター派遣事業であることを確認＝取り違えなし (f)対象は公式上「単胎妊婦（新規追加）・多胎妊婦・3歳未満児養育家庭」へ拡大しており、一次調査の「妊婦または3歳未満児養育家庭」は現行ページと整合（非断定でhedge済み）(g)複数制度の混在なし (h)断定回避・利用料/時間/対象は概括＋「公式で確認」表現あり。支援内容（食事の支度・洗濯・清掃・整理整頓・買い物・健診付き添い・子育て相談）、利用時間（妊婦または3歳未満児' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='katsushika' and t.slug='prenatal-postpartum-helper' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.edogawa.tokyo.jp/e077/kosodate/kosodate/mamapapa_ouentai.html', '検証完了。program.officialUrl（https://www.city.edogawa.tokyo.jp/e077/kosodate/kosodate/mamapapa_ouentai.html）をWebFetchで再取得し、一次調査の各点を照合した。(a)到達OK。(b)許可ホスト＝www.city.edogawa.tokyo.jp（city.*＋.tokyo.jp）に一致。(c)江戸川区公式の家事・育児支援ヘルパー派遣事業「えどがわママパパ応援隊」の当該区ページで間違いない。(d)受付終了・古い年度の表記なし。令和7年（2025年）10月1日から妊娠中の方も対象追加・年間96時間まで拡充という現行情報を確認。(e)支援内容は「食事の支度・片付け、部屋の掃除、育児の補助、健診や買い物等の外出同行」で「お子さまの預かりやベビーシッターは行いません」と明記。母子の心身ケアを行う産後ケア事業（宿泊/通所/訪問）とは別物のヘルパー派遣事業であることを確認、取り違えなし。(f)対象は「江戸川区内に居住している3歳未満のお子さま、または妊娠中の方がいるご家庭」で、一部を全体と書いてい' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='edogawa' and t.slug='prenatal-postpartum-helper' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
